import numpy as np

def random_horizontal_flip(img: np.ndarray, p: float = 0.5,
                            rng: np.random.Generator = None) -> np.ndarray:
    if rng is None:
        rng = np.random.default_rng()
    if rng.random() < p:
        return img[:, ::-1, :].copy()
    return img.copy()

def random_crop(img: np.ndarray, crop_h: int, crop_w: int,
                rng: np.random.Generator = None) -> np.ndarray:
    if rng is None:
        rng = np.random.default_rng()
    H, W, C = img.shape
    top = rng.integers(0, H - crop_h + 1)
    left = rng.integers(0, W - crop_w + 1)
    return img[top:top+crop_h, left:left+crop_w, :].copy()

def color_jitter(img: np.ndarray, brightness: float = 0.2,
                 rng: np.random.Generator = None) -> np.ndarray:
    if rng is None:
        rng = np.random.default_rng()
    factor = 1.0 + rng.uniform(-brightness, brightness)
    out = img.astype(np.float32) * factor
    out = np.clip(out, 0, 255)
    return out.astype(img.dtype)
